/*
 Placeholder for vendorized Chart.js.
 Recommended: replace this file with the minified Chart.js library (v3.9.1 or compatible).
 Example to download the official file into this path:

  mkdir -p $(dirname "$PWD/gestion_avicola/static/src/lib/chart.min.js")
  curl -L https://cdn.jsdelivr.net/npm/chart.js@3.9.1/dist/chart.min.js -o gestion_avicola/static/src/lib/chart.min.js

 This placeholder provides a CDN fallback when the local file is absent or empty.
*/
(function () {
    if (window.Chart) { return; }
    try {
        // If the real library is present (copied here), it will execute and define window.Chart.
        console.warn('Chart.js placeholder loaded. If charts do not render, please vendor the real Chart.js into this file.');
    } catch (e) {
        console.error('Error in Chart.js placeholder', e);
    }
    // Fallback: try to load from CDN if Chart not available after a short delay
    setTimeout(function () {
        if (window.Chart) { return; }
        var s = document.createElement('script');
        s.src = 'https://cdn.jsdelivr.net/npm/chart.js@3.9.1/dist/chart.min.js';
        s.onload = function () { console.log('Chart.js loaded from CDN fallback'); };
        s.onerror = function () { console.error('Failed to load Chart.js from CDN fallback'); };
        document.head.appendChild(s);
    }, 50);
})();
